-- # Workflow templates v2 — Autom8tion Lab Workflow Library
-- Replaces the placeholder seeded copy with production-ready content
-- pulled from the workflow-library PDF. Updates the latest version_snapshot
-- of each is_system='true' template in place, so future instantiations
-- pick up the new content. Existing instantiated workflows in customer orgs
-- carry their own copy of the older snapshot and are unaffected.

-- Template: New Lead Welcome Sequence
UPDATE automation_template_versions SET definition_snapshot = '{"nodes":[{"id":"n1","type":"trigger","data":{"triggerType":"contact_created","triggerCategory":"event"},"position":{"x":320,"y":60}},{"id":"n2","type":"delay","data":{"delayType":"wait_duration","duration":{"value":2,"unit":"minutes"}},"position":{"x":320,"y":190}},{"id":"n3","type":"action","data":{"actionType":"send_email","config":{"subject":"Welcome to Autom8ion Lab, {{contact.first_name}} 👋","preview_text":"Glad to have you here — quick note from the team","body":"Hey {{contact.first_name}},\n\nThanks for reaching out to Autom8ion Lab. I wanted to personally welcome you and make sure you didn''t disappear into a generic email funnel.\n\nHere''s what happens next:\n→ I''ll send over a few resources we typically share with new contacts\n→ If you''re ready to chat sooner, you can grab time on my calendar here: https://os.autom8ionlab.com/book/capability-briefing\n→ If you have a quick question, just hit reply — this email goes straight to my inbox\n\nA bit about us: We engineer custom AI agents and automation systems for service businesses — the kind of work that takes lead follow-up, client onboarding, and back-office ops off your plate so you stop losing deals to slow response times and manual handoffs.\n\nLooking forward to connecting.\n\nSean Richard\nFounder\nAutom8ion Lab\n698-310-2712 | autom8ionlab.com"}},"position":{"x":320,"y":320}},{"id":"n4","type":"action","data":{"actionType":"update_custom_field","config":{"fieldKey":"lead_status","value":"Welcomed"}},"position":{"x":320,"y":450}},{"id":"n5","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"welcomed"}},"position":{"x":320,"y":580}},{"id":"n6","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"new-lead"}},"position":{"x":320,"y":710}},{"id":"n7","type":"delay","data":{"delayType":"wait_duration","duration":{"value":1,"unit":"days"}},"position":{"x":320,"y":840}},{"id":"c8","type":"condition","data":{"label":"Has the contact replied?","conditions":{"logic":"and","rules":[{"field":"tags","operator":"includes","value":"engaged"}]}},"position":{"x":320,"y":970}},{"id":"n9","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"engaged"}},"position":{"x":600,"y":1100}},{"id":"n10","type":"end","data":{"label":"Engaged — End"},"position":{"x":600,"y":1230}},{"id":"n11","type":"action","data":{"actionType":"send_sms","config":{"body":"Hey {{contact.first_name}}, it''s Sean Richard from Autom8ion Lab. Just making sure my welcome email landed — sometimes they get filtered. Any questions I can answer? Reply STOP to opt out."}},"position":{"x":320,"y":1100}},{"id":"n12","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"welcome-sequence-complete"}},"position":{"x":320,"y":1230}},{"id":"n13","type":"end","data":{"label":"End"},"position":{"x":320,"y":1360}}],"edges":[{"id":"e_n1_n2","source":"n1","target":"n2"},{"id":"e_n2_n3","source":"n2","target":"n3"},{"id":"e_n3_n4","source":"n3","target":"n4"},{"id":"e_n4_n5","source":"n4","target":"n5"},{"id":"e_n5_n6","source":"n5","target":"n6"},{"id":"e_n6_n7","source":"n6","target":"n7"},{"id":"e_n7_c8","source":"n7","target":"c8"},{"id":"e_c8_n9","source":"c8","target":"n9","sourceHandle":"true"},{"id":"e_n9_n10","source":"n9","target":"n10"},{"id":"e_c8_n11","source":"c8","target":"n11","sourceHandle":"false"},{"id":"e_n11_n12","source":"n11","target":"n12"},{"id":"e_n12_n13","source":"n12","target":"n13"}],"viewport":{"x":0,"y":0,"zoom":1},"settings":{"enrollmentRules":{"allow_re_enrollment":"after_completion","stop_existing_on_re_entry":false,"max_concurrent_enrollments":1},"waitTimeoutDays":30,"loggingVerbosity":"standard","failureNotificationUserIds":[],"stopOnResponse":true}}'::jsonb
  WHERE template_id IN (SELECT id FROM automation_templates WHERE name = 'New Lead Welcome Sequence' AND is_system = true)
  AND version_number = (SELECT MAX(version_number) FROM automation_template_versions WHERE template_id IN (SELECT id FROM automation_templates WHERE name = 'New Lead Welcome Sequence' AND is_system = true));

-- Template: Lead Qualification Workflow
UPDATE automation_template_versions SET definition_snapshot = '{"nodes":[{"id":"n1","type":"trigger","data":{"triggerType":"form_submitted","triggerCategory":"event"},"position":{"x":320,"y":60}},{"id":"n2","type":"action","data":{"actionType":"ai_prompt","config":{"promptTemplate":"You are a B2B lead qualification expert for Autom8ion Lab, which sells custom AI agents, workflow automation, and intelligent business process systems for service businesses.\n\nOur ideal customer:\n- Industry: [LIST INDUSTRIES]\n- Company size: [SIZE RANGE]\n- Role: Owner, founder, COO, or marketing/ops director\n- Budget: $[MIN] - $[MAX] for our services\n- Timeline: Looking to buy within 90 days\n\nScore this lead from 0-100 based on the form data below. Use this rubric:\n- 70-100: Strong fit, sales-ready (matches industry, size, role, has budget, near-term timeline)\n- 40-69: Partial fit (matches some criteria, may need nurture)\n- 0-39: Poor fit (wrong industry, no budget, or no timeline)\n\nLead data:\n- Name: {{contact.first_name}} {{contact.last_name}}\n- Email: {{contact.email}}\n- Company: {{contact.company_name}}\n- Role: {{contact.job_title}}\n- Form responses: {{form.responses}}\n\nReturn ONLY the numeric score (e.g. \"78\"). No explanation.","outputField":"lead_score"}},"position":{"x":320,"y":190}},{"id":"n3","type":"delay","data":{"delayType":"wait_duration","duration":{"value":30,"unit":"minutes"}},"position":{"x":320,"y":320}},{"id":"c4","type":"condition","data":{"label":"Lead score ≥ 70 (HOT)?","conditions":{"logic":"and","rules":[{"field":"lead_score","operator":"greater_than_or_equal","value":70}]}},"position":{"x":320,"y":450}},{"id":"n5","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"hot-lead"}},"position":{"x":600,"y":580}},{"id":"n6","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"sales-ready"}},"position":{"x":600,"y":710}},{"id":"n7","type":"action","data":{"actionType":"update_custom_field","config":{"fieldKey":"lifecycle_stage","value":"MQL"}},"position":{"x":600,"y":840}},{"id":"n8","type":"action","data":{"actionType":"assign_contact_owner","config":{"strategy":"round_robin"}},"position":{"x":600,"y":970}},{"id":"n9","type":"action","data":{"actionType":"send_internal_notification","config":{"title":"🔥 HOT LEAD — Score: {{contact.lead_score}}","body":"{{contact.first_name}} {{contact.last_name}} ({{contact.company_name}}) — {{contact.phone}} | {{contact.email}}\nCall within 5 minutes for best conversion rate."}},"position":{"x":600,"y":1100}},{"id":"n10","type":"action","data":{"actionType":"create_task","config":{"title":"Call hot lead {{contact.first_name}} {{contact.last_name}} within 5 minutes","priority":"high","due_in_minutes":5}},"position":{"x":600,"y":1230}},{"id":"n11","type":"action","data":{"actionType":"send_email","config":{"subject":"{{contact.first_name}}, let''s get you on the calendar","body":"{{contact.first_name}},\n\nGot your inquiry — based on what you shared, this looks like exactly the kind of project we work on every day.\n\nI want to skip the back-and-forth. Here''s a link to my calendar with 15-minute openings this week: https://os.autom8ionlab.com/book/capability-briefing\n\nOn the call we''ll cover:\n→ Where you''re at right now with [PAIN POINT]\n→ What \"solved\" looks like for you\n→ Whether we''re the right fit (and if not, who is)\n\nIf today''s not the right time but you''ve got a quick question, hit reply.\n\nTalk soon,\nSean Richard"}},"position":{"x":600,"y":1360}},{"id":"n12","type":"end","data":{"label":"Hot — End"},"position":{"x":600,"y":1490}},{"id":"c13","type":"condition","data":{"label":"Lead score ≥ 40 (WARM)?","conditions":{"logic":"and","rules":[{"field":"lead_score","operator":"greater_than_or_equal","value":40}]}},"position":{"x":320,"y":580}},{"id":"n14","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"warm-lead"}},"position":{"x":600,"y":710}},{"id":"n15","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"nurture"}},"position":{"x":600,"y":840}},{"id":"n16","type":"action","data":{"actionType":"update_custom_field","config":{"fieldKey":"lifecycle_stage","value":"Lead"}},"position":{"x":600,"y":970}},{"id":"n17","type":"action","data":{"actionType":"send_email","config":{"subject":"Quick resource based on what you shared, {{contact.first_name}}","body":"Hey {{contact.first_name}},\n\nThanks for filling out the form. Based on your responses, I put together a quick resource that should help: [LINK TO GUIDE / CASE STUDY]\n\nA lot of folks in your spot are wrestling with the same things — [TOP 1-2 PAIN POINTS]. The guide walks through how we''ve solved it for clients in [INDUSTRY].\n\nIf after reading it you''d like to chat, my calendar is here: https://os.autom8ionlab.com/book/capability-briefing\n\nNo pressure either way.\n\nSean Richard\nAutom8ion Lab"}},"position":{"x":600,"y":1100}},{"id":"n18","type":"end","data":{"label":"Warm — End"},"position":{"x":600,"y":1230}},{"id":"n19","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"cold-lead"}},"position":{"x":320,"y":710}},{"id":"n20","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"low-priority"}},"position":{"x":320,"y":840}},{"id":"n21","type":"action","data":{"actionType":"update_custom_field","config":{"fieldKey":"lifecycle_stage","value":"Subscriber"}},"position":{"x":320,"y":970}},{"id":"n22","type":"action","data":{"actionType":"send_email","config":{"subject":"Thanks for reaching out, {{contact.first_name}}","body":"Hi {{contact.first_name}},\n\nThanks for getting in touch. Based on what you shared, we may not be the right fit right now, but I want to keep you in the loop with the kind of resources we share with our community.\n\nI''ll send over our monthly insights — practical tactics on automation, AI, and operations. Unsubscribe anytime.\n\nIf your situation changes and you''d like to reconnect, just reply to any email.\n\nBest,\nSean Richard"}},"position":{"x":320,"y":1100}},{"id":"n23","type":"end","data":{"label":"Cold — End"},"position":{"x":320,"y":1230}}],"edges":[{"id":"e_n1_n2","source":"n1","target":"n2"},{"id":"e_n2_n3","source":"n2","target":"n3"},{"id":"e_n3_c4","source":"n3","target":"c4"},{"id":"e_c4_n5","source":"c4","target":"n5","sourceHandle":"true"},{"id":"e_n5_n6","source":"n5","target":"n6"},{"id":"e_n6_n7","source":"n6","target":"n7"},{"id":"e_n7_n8","source":"n7","target":"n8"},{"id":"e_n8_n9","source":"n8","target":"n9"},{"id":"e_n9_n10","source":"n9","target":"n10"},{"id":"e_n10_n11","source":"n10","target":"n11"},{"id":"e_n11_n12","source":"n11","target":"n12"},{"id":"e_c4_c13","source":"c4","target":"c13","sourceHandle":"false"},{"id":"e_c13_n14","source":"c13","target":"n14","sourceHandle":"true"},{"id":"e_n14_n15","source":"n14","target":"n15"},{"id":"e_n15_n16","source":"n15","target":"n16"},{"id":"e_n16_n17","source":"n16","target":"n17"},{"id":"e_n17_n18","source":"n17","target":"n18"},{"id":"e_c13_n19","source":"c13","target":"n19","sourceHandle":"false"},{"id":"e_n19_n20","source":"n19","target":"n20"},{"id":"e_n20_n21","source":"n20","target":"n21"},{"id":"e_n21_n22","source":"n21","target":"n22"},{"id":"e_n22_n23","source":"n22","target":"n23"}],"viewport":{"x":0,"y":0,"zoom":1},"settings":{"enrollmentRules":{"allow_re_enrollment":"after_completion","stop_existing_on_re_entry":false,"max_concurrent_enrollments":1},"waitTimeoutDays":30,"loggingVerbosity":"standard","failureNotificationUserIds":[]}}'::jsonb
  WHERE template_id IN (SELECT id FROM automation_templates WHERE name = 'Lead Qualification Workflow' AND is_system = true)
  AND version_number = (SELECT MAX(version_number) FROM automation_template_versions WHERE template_id IN (SELECT id FROM automation_templates WHERE name = 'Lead Qualification Workflow' AND is_system = true));

-- Template: Follow-Up After No Response
UPDATE automation_template_versions SET definition_snapshot = '{"nodes":[{"id":"n1","type":"trigger","data":{"triggerType":"contact_tag_changed","triggerCategory":"event","triggerConfig":{"tagName":"awaiting-response"}},"position":{"x":320,"y":60}},{"id":"n2","type":"delay","data":{"delayType":"wait_duration","duration":{"value":3,"unit":"days"}},"position":{"x":320,"y":190}},{"id":"c3","type":"condition","data":{"label":"Replied?","conditions":{"logic":"and","rules":[{"field":"tags","operator":"includes","value":"engaged"}]}},"position":{"x":320,"y":320}},{"id":"n4","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"engaged"}},"position":{"x":600,"y":450}},{"id":"n5","type":"end","data":{"label":"End"},"position":{"x":600,"y":580}},{"id":"n6","type":"action","data":{"actionType":"send_email","config":{"subject":"Following up, {{contact.first_name}}","body":"Hey {{contact.first_name}},\n\nWanted to bump my last email to the top of your inbox in case it slipped through.\n\nQuick recap: [1-LINE SUMMARY OF ORIGINAL OFFER OR ASK].\n\nIf now''s not the right time, no worries at all — just let me know and I''ll back off. If it is, here''s my calendar: https://os.autom8ionlab.com/book/capability-briefing\n\nSean Richard"}},"position":{"x":320,"y":450}},{"id":"n7","type":"delay","data":{"delayType":"wait_duration","duration":{"value":2,"unit":"days"}},"position":{"x":320,"y":580}},{"id":"c8","type":"condition","data":{"label":"Replied?","conditions":{"logic":"and","rules":[{"field":"tags","operator":"includes","value":"engaged"}]}},"position":{"x":320,"y":710}},{"id":"n9","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"engaged"}},"position":{"x":600,"y":840}},{"id":"n10","type":"end","data":{"label":"End"},"position":{"x":600,"y":970}},{"id":"n11","type":"action","data":{"actionType":"send_sms","config":{"body":"Hey {{contact.first_name}}, Sean Richard here — just checking if my last email landed. Easier to text than email? Happy to chat that way too. Reply STOP to opt out."}},"position":{"x":320,"y":840}},{"id":"n12","type":"delay","data":{"delayType":"wait_duration","duration":{"value":3,"unit":"days"}},"position":{"x":320,"y":970}},{"id":"c13","type":"condition","data":{"label":"Replied?","conditions":{"logic":"and","rules":[{"field":"tags","operator":"includes","value":"engaged"}]}},"position":{"x":320,"y":1100}},{"id":"n14","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"engaged"}},"position":{"x":600,"y":1230}},{"id":"n15","type":"end","data":{"label":"End"},"position":{"x":600,"y":1360}},{"id":"n16","type":"action","data":{"actionType":"send_email","config":{"subject":"Should I close your file, {{contact.first_name}}?","body":"{{contact.first_name}},\n\nI''ve reached out a few times and haven''t heard back, which usually means one of three things:\n\n1. You''re slammed and this isn''t a priority right now\n2. You''re not interested and I should stop following up\n3. You fell off a cliff (in which case, hope you''re OK)\n\nA one-word reply is all I need: 1, 2, or 3. Whichever it is, I''ll respect it.\n\nIf I don''t hear back, I''ll assume #2 and close your file — no hard feelings.\n\nSean Richard"}},"position":{"x":320,"y":1230}},{"id":"n17","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"no-response"}},"position":{"x":320,"y":1360}},{"id":"n18","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"cold"}},"position":{"x":320,"y":1490}},{"id":"n19","type":"action","data":{"actionType":"update_custom_field","config":{"fieldKey":"lead_status","value":"Unresponsive"}},"position":{"x":320,"y":1620}},{"id":"n20","type":"action","data":{"actionType":"remove_tag","config":{"tagId":"","tagName":"awaiting-response"}},"position":{"x":320,"y":1750}},{"id":"n21","type":"end","data":{"label":"End"},"position":{"x":320,"y":1880}}],"edges":[{"id":"e_n1_n2","source":"n1","target":"n2"},{"id":"e_n2_c3","source":"n2","target":"c3"},{"id":"e_c3_n4","source":"c3","target":"n4","sourceHandle":"true"},{"id":"e_n4_n5","source":"n4","target":"n5"},{"id":"e_c3_n6","source":"c3","target":"n6","sourceHandle":"false"},{"id":"e_n6_n7","source":"n6","target":"n7"},{"id":"e_n7_c8","source":"n7","target":"c8"},{"id":"e_c8_n9","source":"c8","target":"n9","sourceHandle":"true"},{"id":"e_n9_n10","source":"n9","target":"n10"},{"id":"e_c8_n11","source":"c8","target":"n11","sourceHandle":"false"},{"id":"e_n11_n12","source":"n11","target":"n12"},{"id":"e_n12_c13","source":"n12","target":"c13"},{"id":"e_c13_n14","source":"c13","target":"n14","sourceHandle":"true"},{"id":"e_n14_n15","source":"n14","target":"n15"},{"id":"e_c13_n16","source":"c13","target":"n16","sourceHandle":"false"},{"id":"e_n16_n17","source":"n16","target":"n17"},{"id":"e_n17_n18","source":"n17","target":"n18"},{"id":"e_n18_n19","source":"n18","target":"n19"},{"id":"e_n19_n20","source":"n19","target":"n20"},{"id":"e_n20_n21","source":"n20","target":"n21"}],"viewport":{"x":0,"y":0,"zoom":1},"settings":{"enrollmentRules":{"allow_re_enrollment":"after_completion","stop_existing_on_re_entry":false,"max_concurrent_enrollments":1},"waitTimeoutDays":30,"loggingVerbosity":"standard","failureNotificationUserIds":[],"stopOnResponse":true}}'::jsonb
