-- Template: Appointment Reminder Sequence
UPDATE automation_template_versions SET definition_snapshot = '{"nodes":[{"id":"n1","type":"trigger","data":{"triggerType":"appointment_booked","triggerCategory":"event"},"position":{"x":320,"y":60}},{"id":"n2","type":"action","data":{"actionType":"send_email","config":{"subject":"Confirmed: {{appointment.title}} on {{appointment.start_date}}","body":"{{contact.first_name}}, you''re booked. ✅\n\nHere are your details:\n📅 Date: {{appointment.start_date}}\n⏰ Time: {{appointment.start_time}} ({{appointment.timezone}})\n📍 Location: {{appointment.location}}\n👤 With: {{appointment.assigned_user_name}}\n\nWhat to expect:\n- We''ll start on time — please join 1-2 minutes early\n- Have any prep questions ready\n- The call is roughly {{appointment.duration}} minutes\n\nNeed to reschedule? Use this link: [RESCHEDULE LINK]\nNeed to cancel? [CANCEL LINK]\n\nLooking forward to it.\n\nSean Richard\nAutom8ion Lab"}},"position":{"x":320,"y":190}},{"id":"n3","type":"delay","data":{"delayType":"wait_duration","duration":{"value":1,"unit":"days"}},"position":{"x":320,"y":320}},{"id":"c4","type":"condition","data":{"label":"Appointment still active?","conditions":{"logic":"and","rules":[{"field":"appointment.status","operator":"not_equals","value":"canceled"}]}},"position":{"x":320,"y":450}},{"id":"n5","type":"action","data":{"actionType":"send_sms","config":{"body":"Hi {{contact.first_name}} — quick reminder you''re scheduled with Autom8ion Lab tomorrow at {{appointment.start_time}}. Reply C to confirm or R to reschedule. Looking forward to it!"}},"position":{"x":600,"y":580}},{"id":"n6","type":"delay","data":{"delayType":"wait_duration","duration":{"value":23,"unit":"hours"}},"position":{"x":600,"y":710}},{"id":"c7","type":"condition","data":{"label":"Still active?","conditions":{"logic":"and","rules":[{"field":"appointment.status","operator":"not_equals","value":"canceled"}]}},"position":{"x":600,"y":840}},{"id":"n8","type":"action","data":{"actionType":"send_sms","config":{"body":"{{contact.first_name}}, your call with Sean Richard is in 1 hour ({{appointment.start_time}}). Join link: {{appointment.meeting_url}} — see you soon!"}},"position":{"x":880,"y":970}},{"id":"n9","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"appointment-reminded"}},"position":{"x":880,"y":1100}},{"id":"n10","type":"end","data":{"label":"End"},"position":{"x":880,"y":1230}},{"id":"n11","type":"end","data":{"label":"Canceled — End"},"position":{"x":600,"y":970}},{"id":"n12","type":"end","data":{"label":"Canceled — End"},"position":{"x":320,"y":580}}],"edges":[{"id":"e_n1_n2","source":"n1","target":"n2"},{"id":"e_n2_n3","source":"n2","target":"n3"},{"id":"e_n3_c4","source":"n3","target":"c4"},{"id":"e_c4_n5","source":"c4","target":"n5","sourceHandle":"true"},{"id":"e_n5_n6","source":"n5","target":"n6"},{"id":"e_n6_c7","source":"n6","target":"c7"},{"id":"e_c7_n8","source":"c7","target":"n8","sourceHandle":"true"},{"id":"e_n8_n9","source":"n8","target":"n9"},{"id":"e_n9_n10","source":"n9","target":"n10"},{"id":"e_c7_n11","source":"c7","target":"n11","sourceHandle":"false"},{"id":"e_c4_n12","source":"c4","target":"n12","sourceHandle":"false"}],"viewport":{"x":0,"y":0,"zoom":1},"settings":{"enrollmentRules":{"allow_re_enrollment":"after_completion","stop_existing_on_re_entry":false,"max_concurrent_enrollments":1},"waitTimeoutDays":30,"loggingVerbosity":"standard","failureNotificationUserIds":[]}}'::jsonb
  WHERE template_id IN (SELECT id FROM automation_templates WHERE name = 'Appointment Reminder Sequence' AND is_system = true)
  AND version_number = (SELECT MAX(version_number) FROM automation_template_versions WHERE template_id IN (SELECT id FROM automation_templates WHERE name = 'Appointment Reminder Sequence' AND is_system = true));

-- Template: Post-Meeting Follow-Up
UPDATE automation_template_versions SET definition_snapshot = '{"nodes":[{"id":"n1","type":"trigger","data":{"triggerType":"appointment_status_changed","triggerCategory":"event","triggerConfig":{"newStatus":"showed"}},"position":{"x":320,"y":60}},{"id":"n2","type":"action","data":{"actionType":"ai_prompt","config":{"promptTemplate":"You are writing a post-meeting follow-up email on behalf of Sean Richard at Autom8ion Lab.\n\nMeeting context:\n- Attendee: {{contact.first_name}} {{contact.last_name}} from {{contact.company_name}}\n- Meeting topic: {{appointment.title}}\n- Meeting notes/transcript: {{meeting.notes}}\n\nWrite a follow-up email that:\n1. Thanks them for their time (briefly — one line)\n2. Recaps the 2-3 most important things discussed (bulleted)\n3. Lists the agreed next steps with owners (who does what)\n4. Includes a soft close-the-loop CTA (book next meeting / approve proposal / etc.)\n\nTone: Professional but warm. Conversational, not corporate. Short sentences.\nLength: 150-200 words max.\n\nDo NOT include subject line or signature — just the body.","outputField":"ai_followup_body"}},"position":{"x":320,"y":190}},{"id":"n3","type":"delay","data":{"delayType":"wait_duration","duration":{"value":1,"unit":"hours"}},"position":{"x":320,"y":320}},{"id":"n4","type":"action","data":{"actionType":"send_email","config":{"subject":"Recap & next steps from our call, {{contact.first_name}}","body":"{{ai_followup_body}}\n\nIf anything in this recap is off or incomplete, just hit reply — happy to adjust.\n\nSean Richard\nFounder, Autom8ion Lab"}},"position":{"x":320,"y":450}},{"id":"n5","type":"action","data":{"actionType":"create_task","config":{"title":"Follow up with {{contact.first_name}} re: {{appointment.title}}","due_in_days":3}},"position":{"x":320,"y":580}},{"id":"n6","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"met-with-sales"}},"position":{"x":320,"y":710}},{"id":"n7","type":"action","data":{"actionType":"update_custom_field","config":{"fieldKey":"last_meeting_date","value":"{{date.today}}"}},"position":{"x":320,"y":840}},{"id":"n8","type":"delay","data":{"delayType":"wait_duration","duration":{"value":3,"unit":"days"}},"position":{"x":320,"y":970}},{"id":"c9","type":"condition","data":{"label":"Replied since meeting?","conditions":{"logic":"and","rules":[{"field":"tags","operator":"includes","value":"engaged-post-meeting"}]}},"position":{"x":320,"y":1100}},{"id":"n10","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"engaged-post-meeting"}},"position":{"x":600,"y":1230}},{"id":"n11","type":"end","data":{"label":"End"},"position":{"x":600,"y":1360}},{"id":"n12","type":"action","data":{"actionType":"send_sms","config":{"body":"Hey {{contact.first_name}}, Sean Richard here. Just circling back on our call from earlier this week — any questions on what we discussed? Happy to jump on a quick call if helpful."}},"position":{"x":320,"y":1230}},{"id":"n13","type":"delay","data":{"delayType":"wait_duration","duration":{"value":4,"unit":"days"}},"position":{"x":320,"y":1360}},{"id":"c14","type":"condition","data":{"label":"Replied?","conditions":{"logic":"and","rules":[{"field":"tags","operator":"includes","value":"engaged-post-meeting"}]}},"position":{"x":320,"y":1490}},{"id":"n15","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"engaged-post-meeting"}},"position":{"x":600,"y":1620}},{"id":"n16","type":"end","data":{"label":"End"},"position":{"x":600,"y":1750}},{"id":"n17","type":"action","data":{"actionType":"send_email","config":{"subject":"Should we keep this on the calendar, {{contact.first_name}}?","body":"{{contact.first_name}},\n\nIt''s been about a week since we connected. I want to make sure I''m not chasing if the timing''s just not right.\n\nWhere''s your head at?\n\nA) Still interested — let''s keep moving\nB) Interested but not right now — circle back in [X] months\nC) Not the right fit after all — close the file\n\nWhichever it is, I''ll respect it.\n\nSean Richard"}},"position":{"x":320,"y":1620}},{"id":"n18","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"post-meeting-no-response"}},"position":{"x":320,"y":1750}},{"id":"n19","type":"end","data":{"label":"End"},"position":{"x":320,"y":1880}}],"edges":[{"id":"e_n1_n2","source":"n1","target":"n2"},{"id":"e_n2_n3","source":"n2","target":"n3"},{"id":"e_n3_n4","source":"n3","target":"n4"},{"id":"e_n4_n5","source":"n4","target":"n5"},{"id":"e_n5_n6","source":"n5","target":"n6"},{"id":"e_n6_n7","source":"n6","target":"n7"},{"id":"e_n7_n8","source":"n7","target":"n8"},{"id":"e_n8_c9","source":"n8","target":"c9"},{"id":"e_c9_n10","source":"c9","target":"n10","sourceHandle":"true"},{"id":"e_n10_n11","source":"n10","target":"n11"},{"id":"e_c9_n12","source":"c9","target":"n12","sourceHandle":"false"},{"id":"e_n12_n13","source":"n12","target":"n13"},{"id":"e_n13_c14","source":"n13","target":"c14"},{"id":"e_c14_n15","source":"c14","target":"n15","sourceHandle":"true"},{"id":"e_n15_n16","source":"n15","target":"n16"},{"id":"e_c14_n17","source":"c14","target":"n17","sourceHandle":"false"},{"id":"e_n17_n18","source":"n17","target":"n18"},{"id":"e_n18_n19","source":"n18","target":"n19"}],"viewport":{"x":0,"y":0,"zoom":1},"settings":{"enrollmentRules":{"allow_re_enrollment":"after_completion","stop_existing_on_re_entry":false,"max_concurrent_enrollments":1},"waitTimeoutDays":30,"loggingVerbosity":"standard","failureNotificationUserIds":[],"stopOnResponse":true}}'::jsonb
