UPDATE automation_template_versions SET definition_snapshot = '{"nodes":[{"id":"n1","type":"trigger","data":{"triggerType":"contact_tag_changed","triggerCategory":"event","triggerConfig":{"tagName":"proposal-sent"}},"position":{"x":320,"y":60}},{"id":"n2","type":"action","data":{"actionType":"send_email","config":{"subject":"Your proposal from Autom8ion Lab, {{contact.first_name}}","body":"{{contact.first_name}},\n\nAs promised, your proposal is attached / linked below:\n\n📄 [PROPOSAL LINK]\n\nA quick guide to reviewing it:\n→ Page 1-2: What we''ll deliver and the scope\n→ Page 3: Timeline and milestones\n→ Page 4: Investment and payment terms\n→ Page 5: Acceptance — sign right inside the document\n\nIf anything raises a question, reply to this email or text me at 698-310-2712.\n\nOnce you''re ready, hit \"Approve\" inside the proposal and we''ll get the kickoff scheduled within 24 hours.\n\nSean Richard\nAutom8ion Lab"}},"position":{"x":320,"y":190}},{"id":"n3","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"pending"}},"position":{"x":320,"y":320}},{"id":"n4","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"proposal-active"}},"position":{"x":320,"y":450}},{"id":"n5","type":"action","data":{"actionType":"update_custom_field","config":{"fieldKey":"lifecycle_stage","value":"Proposal Sent"}},"position":{"x":320,"y":580}},{"id":"n6","type":"delay","data":{"delayType":"wait_duration","duration":{"value":3,"unit":"days"}},"position":{"x":320,"y":710}},{"id":"c7","type":"condition","data":{"label":"Proposal signed/paid or replied?","conditions":{"logic":"and","rules":[{"field":"tags","operator":"includes","value":"proposal-engaged"}]}},"position":{"x":320,"y":840}},{"id":"n8","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"proposal-engaged"}},"position":{"x":600,"y":970}},{"id":"n9","type":"end","data":{"label":"End"},"position":{"x":600,"y":1100}},{"id":"n10","type":"action","data":{"actionType":"send_email","config":{"subject":"Quick check-in on the proposal, {{contact.first_name}}","body":"Hey {{contact.first_name}},\n\nWanted to follow up on the proposal I sent over a few days ago. No pressure — I know these decisions take time and there are usually a few stakeholders involved.\n\nA few quick notes that might help:\n→ If you have questions on scope, pricing, or timeline, I''m happy to jump on a 10-minute call to walk through it: https://os.autom8ionlab.com/book/capability-briefing\n→ If you need to share it internally, the link is: [PROPOSAL LINK]\n→ If anything needs to change to make it a yes, tell me what and we''ll figure it out\n\nWhat''s the best next step from your side?\n\nSean Richard"}},"position":{"x":320,"y":970}},{"id":"n11","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"proposal-followup-sent"}},"position":{"x":320,"y":1100}},{"id":"n12","type":"end","data":{"label":"End"},"position":{"x":320,"y":1230}}],"edges":[{"id":"e_n1_n2","source":"n1","target":"n2"},{"id":"e_n2_n3","source":"n2","target":"n3"},{"id":"e_n3_n4","source":"n3","target":"n4"},{"id":"e_n4_n5","source":"n4","target":"n5"},{"id":"e_n5_n6","source":"n5","target":"n6"},{"id":"e_n6_c7","source":"n6","target":"c7"},{"id":"e_c7_n8","source":"c7","target":"n8","sourceHandle":"true"},{"id":"e_n8_n9","source":"n8","target":"n9"},{"id":"e_c7_n10","source":"c7","target":"n10","sourceHandle":"false"},{"id":"e_n10_n11","source":"n10","target":"n11"},{"id":"e_n11_n12","source":"n11","target":"n12"}],"viewport":{"x":0,"y":0,"zoom":1},"settings":{"enrollmentRules":{"allow_re_enrollment":"after_completion","stop_existing_on_re_entry":false,"max_concurrent_enrollments":1},"waitTimeoutDays":30,"loggingVerbosity":"standard","failureNotificationUserIds":[]}}'::jsonb
