UPDATE automation_template_versions SET definition_snapshot = '{"nodes":[{"id":"n1","type":"trigger","data":{"triggerType":"invoice_overdue","triggerCategory":"event"},"position":{"x":320,"y":60}},{"id":"n2","type":"delay","data":{"delayType":"wait_duration","duration":{"value":30,"unit":"days"}},"position":{"x":320,"y":190}},{"id":"c3","type":"condition","data":{"label":"Already a customer?","conditions":{"logic":"and","rules":[{"field":"tags","operator":"includes","value":"customer"}]}},"position":{"x":320,"y":320}},{"id":"n4","type":"end","data":{"label":"Already a customer — End"},"position":{"x":600,"y":450}},{"id":"n5","type":"action","data":{"actionType":"send_email","config":{"subject":"Has anything changed on your end, {{contact.first_name}}?","body":"Hey {{contact.first_name}},\n\nIt''s been about a month since we last spoke and I wanted to check in — no agenda, just genuinely curious.\n\nWhen we talked, you were dealing with [PAIN POINT FROM PREVIOUS CONVO — IF NO CUSTOM FIELD, KEEP GENERIC: \"the challenges around [TOPIC]\"]. A lot can change in 30 days.\n\nThree quick questions:\n1. Did you end up solving it another way?\n2. Did the priority shift to something else?\n3. Or is it still on the list and the timing just hasn''t been right?\n\nIf it''s #3 and you''d like to revisit, I''ve got time this week: https://os.autom8ionlab.com/book/capability-briefing\n\nIf it''s #1 or #2, I''d love to hear what you ended up doing — always learning from how folks solve this stuff.\n\nEither way, no pressure.\n\nSean Richard\nAutom8ion Lab"}},"position":{"x":320,"y":450}},{"id":"n6","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"win-back-attempt"}},"position":{"x":320,"y":580}},{"id":"n7","type":"action","data":{"actionType":"add_tag","config":{"tagId":"","tagName":"re-engaged-30d"}},"position":{"x":320,"y":710}},{"id":"n8","type":"action","data":{"actionType":"update_custom_field","config":{"fieldKey":"last_engagement_date","value":"{